declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('customers.view');$pageTitle='Viewer Accounts';require VP3_ROOT.'/includes/admin-header.php';$rows=vp3_db()->query("SELECT va.id,va.viewer_uuid,va.display_name,va.handle,va.email,va.status,va.profile_visibility,va.email_verified_at,va.last_login_at,va.created_at,(SELECT COUNT(*) FROM viewer_watch_history h WHERE h.viewer_id=va.id) history_count,(SELECT COUNT(*) FROM viewer_clip_actions a WHERE a.viewer_id=va.id AND a.action_type='save') saved_count FROM viewer_accounts va ORDER BY va.id DESC LIMIT 300")->fetchAll();?>
<div class="admin-page-head"><div><span class="admin-kicker">VP3 Reels</span><h1>Viewer accounts</h1><p>Review viewer identity, verification, account status, saved-library size, and watch-history activity without exposing passwords or private tokens.</p></div></div><div class="table-wrap"><table class="table"><thead><tr><th>Viewer</th><th>Email</th><th>Status</th><th>Library</th><th>Last login</th><th>Created</th><th></th></tr></thead><tbody><?php foreach($rows as$row):?><tr><td><b><?=vp3_e($row['display_name'])?></b><br><small>@<?=vp3_e($row['handle'])?> · <?=vp3_e($row['profile_visibility'])?></small></td><td><?=vp3_e($row['email'])?><br><small><?=$row['email_verified_at']?'Verified':'Pending verification'?></small></td><td><span class="badge <?=vp3_e($row['status'])?>"><?=vp3_e($row['status'])?></span></td><td><?=number_format((int)$row['saved_count'])?> saved<br><small><?=number_format((int)$row['history_count'])?> watched</small></td><td><?=vp3_e((string)($row['last_login_at']?:'—'))?></td><td><?=vp3_e($row['created_at'])?></td><td><a href="viewer.php?id=<?=(int)$row['id']?>">Open</a></td></tr><?php endforeach;?></tbody></table></div>
